    if (!started || score !== null) return
    const t = setInterval(() => {
      setSecondsLeft((s) => {
        if (s <= 1) {
          clearInterval(t)
          finishTest()
          return 0
        }
        return s - 1
      })
    }, 1000)
    return () => clearInterval(t)
  }, [started, score])

  const finishTest = useCallback(() => {
    let correct = 0
    answers.forEach((a, i) => {
      if (questions[i] && a === questions[i].correctIndex) correct += 1
    })
    setScore(Math.round((correct / Math.max(questions.length, 1)) * 100))
  }, [questions])

  const [answers, setAnswers] = useState<(number | null)[]>([])

  useEffect(() => {
    setAnswers(Array(questions.length).fill(null))
    setPicked(null)
    setIdx(0)
    setScore(null)
    setStarted(false)
    setSecondsLeft(15 * 60)
  }, [questions])

  const selectOption = (optionIndex: number) => {
    setPicked(optionIndex)
    setAnswers((prev) => {
      const next = [...prev]
      next[idx] = optionIndex
      return next
    })
  }

  const nextQ = () => {
    if (idx < questions.length - 1) {
      setIdx((i) => i + 1)
      setPicked(answers[idx + 1] ?? null)
    } else {
      finishWithAnswers()
    }
  }

  const finishWithAnswers = () => {
    let correct = 0
    answers.forEach((a, i) => {
      if (questions[i] && a === questions[i].correctIndex) correct += 1
    })
    const last = picked !== null ? [...answers] : answers
    if (picked !== null) last[idx] = picked
    last.forEach((a, i) => {
      if (questions[i] && a === questions[i].correctIndex) correct += 1
    })
    const total = questions.length
    const c = last.reduce((acc, a, i) => acc + (questions[i] && a === questions[i].correctIndex ? 1 : 0), 0)
    setScore(Math.round((c / Math.max(total, 1)) * 100))
  }

  if (loading) {
    return (
      <div className="flex justify-center py-16">
        <Loader2 className="animate-spin text-primary" size={28} />
      </div>
    )
  }

  if (questions.length === 0) {
    return <p className="text-muted-foreground text-sm">No questions available.</p>
  }

  if (score !== null) {
    return (
      <div className="bg-card border border-border rounded-xl p-8 text-center">
        <h2 className="text-lg font-semibold text-foreground mb-2">Result</h2>
        <p className="text-4xl font-bold text-primary mb-4">{score}%</p>
        <button
          type="button"
          onClick={() => {
            setScore(null)
            setIdx(0)
            setPicked(null)
            setAnswers(Array(questions.length).fill(null))
            setStarted(false)
            setSecondsLeft(15 * 60)
          }}
          className="px-5 py-2 rounded-lg bg-primary text-primary-foreground text-sm font-medium"
        >
          Retry
        </button>
      </div>
    )
  }

  const q = questions[idx]
  const mm = Math.floor(secondsLeft / 60)
  const ss = secondsLeft % 60

  return (
    <div className="space-y-4">
      <div className="bg-card border border-border rounded-xl p-5">
        <div className="flex flex-wrap items-center justify-between gap-3 mb-4">
          <div>
            <h2 className="text-base font-semibold text-foreground">{title}</h2>
            <p className="text-xs text-muted-foreground mt-1">
              {questions.length} questions · sample drill (not persisted)
            </p>
          </div>
          {started && (
            <span className="flex items-center gap-2 text-sm text-muted-foreground tabular-nums">
              <Clock size={16} />
              {mm}:{`${ss}`.padStart(2, '0')}
            </span>
          )}
        </div>

        {!started ? (
          <button
            type="button"
            onClick={() => setStarted(true)}
            className="w-full py-3 rounded-lg bg-primary text-primary-foreground text-sm font-medium hover:brightness-110"
          >
            Start test
          </button>
        ) : (
          <>
            <p className="text-xs text-muted-foreground mb-1">
              {q.subject} · {q.topic}
            </p>
            <p className="text-sm text-foreground mb-4">{q.text}</p>
            <div className="space-y-2">
              {q.options.map((opt, i) => (
                <button
                  key={i}
                  type="button"
                  onClick={() => selectOption(i)}
                  className={`w-full text-left px-3 py-2.5 rounded-lg border text-sm transition-all ${
                    picked === i
                      ? 'border-primary bg-primary/10 text-foreground'
                      : 'border-border hover:bg-secondary/80 text-foreground'
                  }`}
                >
                  <span className="font-medium text-muted-foreground mr-2">{String.fromCharCode(65 + i)}.</span>
                  {opt}
                </button>
              ))}
            </div>
            <div className="flex justify-between items-center mt-6">
              <span className="text-xs text-muted-foreground">
                {idx + 1} / {questions.length}
              </span>
              <button
                type="button"
                onClick={nextQ}
                className="inline-flex items-center gap-1 px-4 py-2 rounded-lg bg-secondary text-sm font-medium hover:bg-secondary/80"
              >
                {idx >= questions.length - 1 ? 'Finish' : 'Next'}
                <ChevronRight size={16} />
              </button>
            </div>
          </>
        )}
      </div>

      <div className="flex flex-wrap gap-2 justify-center">
        {questions.map((_, i) => (
          <button
            key={i}
            type="button"
            disabled={!started}
            onClick={() => {
              setIdx(i)
              setPicked(answers[i] ?? null)
            }}
            className="p-1"
          >
            {answers[i] !== null ? (
              <CheckCircle2 size={18} className="text-primary" />
            ) : (
              <Circle size={18} className="text-muted-foreground/40" />
            )}
          </button>
        ))}
      </div>
    </div>
  )
}

function CreateTestPanel() {
  const [uploading, setUploading] = useState(false)
  const [result, setResult] = useState<Record<string, unknown> | null>(null)

  const onSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault()
    const form = e.currentTarget
    const fd = new FormData(form)
    const file = fd.get('file')
    if (!(file instanceof File) || file.size === 0) {
      toast.error('Choose a PDF file')
      return
    }
    setUploading(true)
    setResult(null)
    try {
      const up = new FormData()
      up.append('file', file)
      up.append('title', file.name)
      const res = await fetch('/api/test/upload-pdf', { method: 'POST', body: up })
      const data = await res.json()
      setResult(data)
      if (data.ok) toast.success('Upload registered (skeleton)')
      else toast.error(data.error ?? 'Upload failed')
    } catch {
      toast.error('Network error')
    } finally {
      setUploading(false)
    }
