import { createClient, type SupabaseClient } from "@supabase/supabase-js";

let cached: SupabaseClient | null = null;

/** Server-only uploads (service role). Never import in client components. */
export function getSupabaseAdmin(): SupabaseClient | null {
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL;
  const key = process.env.SUPABASE_SERVICE_ROLE_KEY;
  if (!url || !key) return null;
  if (!cached) cached = createClient(url, key, { auth: { persistSession: false } });
  return cached;
}

export async function uploadBuffer(args: {
  bucket: string;
  path: string;
  body: Buffer | Blob;
  contentType: string;
}) {
  const sb = getSupabaseAdmin();
  if (!sb) throw new Error("Supabase is not configured (NEXT_PUBLIC_SUPABASE_URL + SUPABASE_SERVICE_ROLE_KEY)");
  const { error } = await sb.storage.from(args.bucket).upload(args.path, args.body, {
    contentType: args.contentType,
    upsert: true,
  });
  if (error) throw error;
  return { path: args.path };
}

export async function getSignedUrl(bucket: string, path: string, expiresSec = 3600) {
  const sb = getSupabaseAdmin();
  if (!sb) throw new Error("Supabase is not configured");
  const { data, error } = await sb.storage.from(bucket).createSignedUrl(path, expiresSec);
  if (error) throw error;
  return data.signedUrl;
}

import { formatISO, startOfDay } from "date-fns";
import type { PrismaClient } from "@prisma/client";

/** Dates (yyyy-MM-dd) where user had meaningful activity */
export async function collectActiveDates(prisma: PrismaClient, userId: string): Promise<Set<string>> {
  const dates = new Set<string>();

  const sessions = await prisma.studySessionLog.findMany({
    where: { userId, durationMinutes: { gt: 0 } },
    select: { startedAt: true },
    take: 500,
  });
  sessions.forEach((s) => dates.add(formatISO(startOfDay(s.startedAt), { representation: "date" })));

  const tasks = await prisma.task.findMany({
    where: { userId, completed: true },
    select: { updatedAt: true },
    take: 500,
  });
  tasks.forEach((t) => dates.add(formatISO(startOfDay(t.updatedAt), { representation: "date" })));

  const reviews = await prisma.flashcardReview.findMany({
    where: { userId },
    select: { reviewedAt: true },
    take: 500,
  });
  reviews.forEach((r) => dates.add(formatISO(startOfDay(r.reviewedAt), { representation: "date" })));

  const attempts = await prisma.testAttempt.findMany({
    where: { userId },
    select: { createdAt: true },
    take: 100,
  });
  attempts.forEach((a) => dates.add(formatISO(startOfDay(a.createdAt), { representation: "date" })));

  return dates;
}

export function consecutiveStreakFromToday(activeDates: Set<string>): number {
  const today = startOfDay(new Date());
  let streak = 0;
  for (let i = 0; i < 366; i++) {
    const d = new Date(today);
    d.setDate(d.getDate() - i);
    const key = formatISO(d, { representation: "date" });
    if (activeDates.has(key)) streak += 1;
    else break;
  }
  return streak;
}

export function consistencyLastNDays(activeDates: Set<string>, n: number): number {
  const today = startOfDay(new Date());
  let hit = 0;
  for (let i = 0; i < n; i++) {
    const d = new Date(today);
    d.setDate(d.getDate() - i);
    const key = formatISO(d, { representation: "date" });
    if (activeDates.has(key)) hit += 1;
  }
  return Math.round((hit / n) * 100);
}

import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { prisma } from "@/lib/prisma";
import { GATE_EXAM_DATE_ISO, USER_DISPLAY_NAME, USER_STREAM_LABEL } from "@/lib/gate-ee";

const DEMO_EMAIL = "nem@gateprep.local";

export async function getEffectiveUserId(): Promise<string | null> {
  try {
    const session = await getServerSession(authOptions);
    if (session?.user?.id) return session.user.id;

    const gateDate = new Date(GATE_EXAM_DATE_ISO);
    const demo = await prisma.user.upsert({
      where: { email: DEMO_EMAIL },
      update: {
        name: USER_DISPLAY_NAME,
        streamLabel: USER_STREAM_LABEL,
        gateDate,
        branch: "EE",
      },
      create: {
        email: DEMO_EMAIL,
        name: USER_DISPLAY_NAME,
        streamLabel: USER_STREAM_LABEL,
        gateDate,
        branch: "EE",
        hoursPerDay: 4,
        weakSubjects: ["Power Systems", "Control Systems"],
      },
    });
    return demo.id;
  } catch {
    return null;
  }
}

