import { NextResponse } from "next/server";
import { differenceInCalendarDays, endOfDay, startOfDay } from "date-fns";
import { prisma } from "@/lib/prisma";
import { getEffectiveUserId } from "@/lib/session";
import { GATE_EE_SUBJECTS, GATE_EXAM_DATE_ISO, SUBJECT_COLORS } from "@/lib/gate-ee";
import {
  collectActiveDates,
  consecutiveStreakFromToday,
  consistencyLastNDays,
} from "@/lib/streak";

export async function GET() {
  const userId = await getEffectiveUserId();
  if (!userId) {
    return NextResponse.json(
      { error: "Database unavailable. Set DATABASE_URL (Supabase Postgres)." },
      { status: 503 },
    );
  }

  const user = await prisma.user.findUnique({ where: { id: userId } });
  const gateDate = user?.gateDate ?? new Date(GATE_EXAM_DATE_ISO);
  const gateCountdown = Math.max(0, differenceInCalendarDays(gateDate, new Date()));

  const dayStart = startOfDay(new Date());
  const dayEnd = endOfDay(new Date());

  const studyAgg = await prisma.studySessionLog.aggregate({
    where: { userId, startedAt: { gte: dayStart, lte: dayEnd } },
    _sum: { durationMinutes: true },
  });
  const hoursToday = Math.round(((studyAgg._sum.durationMinutes ?? 0) / 60) * 10) / 10;

  const tasksCompletedAll = await prisma.task.count({ where: { userId, completed: true } });
  const tasksCompletedToday = await prisma.task.count({
    where: { userId, completed: true, updatedAt: { gte: dayStart, lte: dayEnd } },
  });
  const tasksOpen = await prisma.task.count({ where: { userId, completed: false } });

  const notesCount = await prisma.note.count({ where: { userId } });
  const lecturesCount = await prisma.lecture.count({ where: { userId } });

  const now = new Date();
  const flashcardsDue = await prisma.flashcard.count({
    where: { userId, mastered: false, nextReview: { lte: now } },
  });
  const flashcardsMastered = await prisma.flashcard.count({ where: { userId, mastered: true } });

  const attempts = await prisma.testAttempt.findMany({
    where: { userId },
    orderBy: { createdAt: "asc" },
    take: 16,
  });
  const recentScores = attempts.map((a, i) => ({
    date: `T${i + 1}`,
    score: a.totalQuestions > 0 ? Math.round((a.score / a.totalQuestions) * 100) : 0,
  }));

  const topicPerf = await prisma.topicPerformance.findMany({ where: { userId } });
  const perfMap = Object.fromEntries(
    topicPerf.map((t) => [
      t.subject,
      t.attempts > 0 ? Math.round((100 * t.correct) / t.attempts) : null,
    ]),
  );

  const slots = await prisma.timetableSlot.findMany({ where: { userId } });
  const slotSubjectTotals = new Map<string, { done: number; all: number }>();
  for (const s of GATE_EE_SUBJECTS) slotSubjectTotals.set(s, { done: 0, all: 0 });
  for (const sl of slots) {
    const cur = slotSubjectTotals.get(sl.subject) ?? { done: 0, all: 0 };
    cur.all += 1;
    if (sl.completed) cur.done += 1;
    slotSubjectTotals.set(sl.subject, cur);
  }

  const subjectProgress = GATE_EE_SUBJECTS.map((subject) => {
    const pctFromPerf = perfMap[subject];
    const st = slotSubjectTotals.get(subject)!;
    const pctFromSlots = st.all === 0 ? null : Math.round((100 * st.done) / st.all);
    const progress = pctFromPerf ?? pctFromSlots ?? 0;
    return {
      subject,
      progress: Math.min(100, progress),
      color: SUBJECT_COLORS[subject] ?? "#6C63FF",
    };
  });

  const weakFromPerf = [...topicPerf]
    .filter((t) => t.attempts >= 2)
    .map((t) => ({
      subject: t.subject,
      pct: t.attempts ? (100 * t.correct) / t.attempts : 0,
    }))
    .sort((a, b) => a.pct - b.pct)
    .slice(0, 5)
    .map((w) => w.subject);

  const weakSubjects =
    weakFromPerf.length > 0 ? weakFromPerf : user?.weakSubjects?.length ? user.weakSubjects.slice(0, 5) : [];

  const tasksPreview = await prisma.task.findMany({
    where: { userId },
    orderBy: [{ completed: "asc" }, { dueDate: "asc" }, { createdAt: "desc" }],
    take: 5,
  });

  const activeDates = await collectActiveDates(prisma, userId);
  const streak = consecutiveStreakFromToday(activeDates);
  const consistency = consistencyLastNDays(activeDates, 30);

  await prisma.user.update({
    where: { id: userId },
    data: { studyStreakDays: streak, lastStreakDate: startOfDay(new Date()) },
  });

  const topicsDoneSlots = slots.filter((s) => s.completed).length;

  return NextResponse.json({
    stats: {
      studyStreak: streak,
      hoursToday,
      tasksCompletedToday,
      tasksCompletedAll,
      tasksOpen,
      topicsDone: topicsDoneSlots,
      gateCountdown,
      notesCount,
      lecturesCount,
      flashcardsDue,
      flashcardsMastered,
      studyConsistencyPct: consistency,
      mockTestsTaken: attempts.length,
    },
    subjectProgress,
    recentScores,
    weakSubjects,
    todaysTodos: tasksPreview.map((t) => ({
      id: t.id,
      task: t.title,
      priority: t.priority as "high" | "medium" | "low",
      completed: t.completed,
    })),
    meta: {
      streamLabel: user?.streamLabel ?? "GATE - EE",
      displayName: user?.name ?? "Nem",
    },
  });
}

