type Incoming = {
  dayOfWeek: number;
  startTime: string;
  durationMinutes?: number;
  subject: string;
  topic?: string | null;
};

function normalizeSubject(s: string): string {
  const hit = GATE_EE_SUBJECTS.find((x) => x.toLowerCase() === s.trim().toLowerCase());
  return hit ?? GATE_EE_SUBJECTS[0];
}

export async function POST(req: Request) {
  const userId = await getEffectiveUserId();
  if (!userId) return NextResponse.json({ error: "No database session" }, { status: 503 });
  const body = await req.json();
  const rows = body.slots as Incoming[];
  if (!Array.isArray(rows) || rows.length === 0) {
    return NextResponse.json({ error: "slots[] required" }, { status: 400 });
  }

  await prisma.$transaction(async (tx) => {
    await tx.timetableSlot.deleteMany({ where: { userId } });
    await tx.timetableSlot.createMany({
      data: rows.map((r) => ({
        userId,
        dayOfWeek: Math.min(6, Math.max(0, Number(r.dayOfWeek))),
        startTime: String(r.startTime ?? "09:00"),
        durationMinutes: Math.min(240, Math.max(15, Number(r.durationMinutes ?? 60))),
        subject: normalizeSubject(String(r.subject ?? "Engineering Mathematics")),
        topic: r.topic ? String(r.topic) : null,
        completed: false,
        source: "ai_applied",
      })),
    });
  });

  const slots = await prisma.timetableSlot.findMany({
    where: { userId },
    orderBy: [{ dayOfWeek: "asc" }, { startTime: "asc" }],
  });
  return NextResponse.json({ ok: true, slots });
}

