export function normalizePlanSlots(arr: unknown[] | null): NormalizedSlot[] {
  if (!arr) return [];
  const subjectsLc = new Map(GATE_EE_SUBJECTS.map((s) => [s.toLowerCase(), s]));
  const out: NormalizedSlot[] = [];
