import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { getEffectiveUserId } from "@/lib/session";
import { SAMPLE_EE_QUESTIONS } from "@/lib/sample-test-ee";

export async function POST(req: Request) {
  const userId = await getEffectiveUserId();
  if (!userId) return NextResponse.json({ error: "No database session" }, { status: 503 });

  const body = await req.json();
  const answers = Array.isArray(body.answers) ? body.answers.map(Number) : [];
  const timeTakenSeconds = Math.max(0, Number(body.timeTakenSeconds ?? 0));

  let score = 0;
  const topicBreakdown: Record<string, { correct: number; total: number }> = {};
  const weakTopics: string[] = [];

  SAMPLE_EE_QUESTIONS.forEach((q, i) => {
    const picked = answers[i];
    const ok = picked === q.correctIndex;
    if (ok) score += 1;

    const key = `${q.subject}::${q.topic}`;
    if (!topicBreakdown[key]) topicBreakdown[key] = { correct: 0, total: 0 };
    topicBreakdown[key].total += 1;
    if (ok) topicBreakdown[key].correct += 1;
  });

  const totalQuestions = SAMPLE_EE_QUESTIONS.length;
  const accuracy = totalQuestions > 0 ? (score / totalQuestions) * 100 : 0;

  Object.entries(topicBreakdown).forEach(([k, v]) => {
    const pct = v.total ? (v.correct / v.total) * 100 : 0;
    if (pct < 50 && v.total > 0) weakTopics.push(k.replace('::', ' — '));
  });

  const attempt = await prisma.testAttempt.create({
    data: {
      userId,
      title: String(body.title ?? "Practice EE drill"),
      score,
      totalQuestions,
      timeTakenSeconds,
      correctIndices: SAMPLE_EE_QUESTIONS.map((q) => q.correctIndex),
      userAnswers: answers,
      topicBreakdown,
      weakTopics,
      accuracy,
    },
  });

  for (const q of SAMPLE_EE_QUESTIONS) {
    const picked = answers[SAMPLE_EE_QUESTIONS.indexOf(q)];
    const ok = picked === q.correctIndex;
    await prisma.topicPerformance.upsert({
      where: {
        userId_subject: { userId, subject: q.subject },
      },
      update: {
        attempts: { increment: 1 },
        correct: { increment: ok ? 1 : 0 },
      },
      create: {
        userId,
        subject: q.subject,
        attempts: 1,
        correct: ok ? 1 : 0,
      },
    });
  }

  return NextResponse.json({
    attempt,
    weakTopics,
    accuracy,
    score,
    totalQuestions,
    comparisons: SAMPLE_EE_QUESTIONS.map((q, i) => ({
      subject: q.subject,
      topic: q.topic,
      correctAnswerIndex: q.correctIndex,
      userAnswerIndex: answers[i] ?? null,
      ok: answers[i] === q.correctIndex,
    })),
  });
}
